from collections import deque

class PushRelabel:
    def __init__(self, n):
        self.n = n
        self.adj = [[] for _ in range(n)]
        self.capacities = []
        self.h = [0] * n
        self.e = [0] * n
        self.current_edge_ptr = [0] * n
        self.active_nodes = deque()

    def add_edge(self, u, v, capacity):
        self.adj[u].append([v, len(self.capacities), len(self.adj[v])])
        self.capacities.append(capacity)
        self.adj[v].append([u, len(self.capacities), len(self.adj[u]) - 1])
        self.capacities.append(0)

    def _push(self, u, v, cap_idx, rev_idx, delta):
        self.capacities[cap_idx] -= delta
        self.capacities[rev_idx] += delta
        self.e[u] -= delta
        self.e[v] += delta

    def _relabel(self, u):
        min_h = float('inf')
        for i in range(len(self.adj[u])):
            v, cap_idx, _ = self.adj[u][i]
            if self.capacities[cap_idx] > 0:
                min_h = min(min_h, self.h[v])

        if min_h == float('inf'):
            self.h[u] = self.n
        else:
            self.h[u] = 1 + min_h
        self.current_edge_ptr[u] = 0

    def _discharge(self, u, s, t):
        while self.e[u] > 0:
            if self.current_edge_ptr[u] >= len(self.adj[u]):
                self._relabel(u)
                if self.h[u] >= self.n:
                    break
            else:
                v, cap_idx, rev_idx = self.adj[u][self.current_edge_ptr[u]]

                if self.capacities[cap_idx] > 0 and self.h[u] == self.h[v] + 1:
                    delta = min(self.e[u], self.capacities[cap_idx])

                    if v != s and v != t and self.e[v] == 0:
                        self.active_nodes.append(v)

                    self._push(u, v, cap_idx, rev_idx, delta)
                else:
                    self.current_edge_ptr[u] += 1

    def max_flow(self, s, t):
        self.h[s] = self.n

        for i in range(len(self.adj[s])):
            v, cap_idx, rev_idx = self.adj[s][i]
            capacity_from_s = self.capacities[cap_idx]
            if capacity_from_s > 0:
                self._push(s, v, cap_idx, rev_idx, capacity_from_s)
                if v != s and v != t and self.e[v] > 0:
                    self.active_nodes.append(v)

        while self.active_nodes:
            u = self.active_nodes.popleft()

            if self.e[u] > 0 and u != s and u != t:
                self._discharge(u, s, t)

        return self.e[t]
